package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// Allowed redirect paths - whitelist approach
var allowedRedirectPaths = map[string]bool{
	"https://yourapp.com/callback":       true,
	"https://yourapp.com/auth/callback":  true,
	"https://yourapp.com/oauth/callback": true,
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, stateCookie *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate and sanitize the redirect path
	validatedRedirectURL, err := validateRedirectURL(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Generate a cryptographically secure random state token
	state, err := generateSecureState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Set the state cookie if provided
	if stateCookie != nil && w != nil {
		stateCookie.Value = state
		http.SetCookie(w, stateCookie)
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	return authURL, nil
}

// generateSecureState creates a cryptographically secure random state token
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectURL validates the redirect URL against a whitelist
func validateRedirectURL(redirectPath string) (string, error) {
	// If empty, use the default from config
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Parse the URL to ensure it's valid
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid URL format: %w", err)
	}

	// Ensure the URL is absolute and uses HTTPS
	if !parsedURL.IsAbs() {
		return "", fmt.Errorf("redirect URL must be absolute")
	}

	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return "", fmt.Errorf("redirect URL must use HTTPS or HTTP")
	}

	// Normalize the URL
	normalizedURL := strings.TrimRight(parsedURL.String(), "/")

	// Check against whitelist
	if !allowedRedirectPaths[normalizedURL] {
		return "", fmt.Errorf("redirect URL not in whitelist")
	}

	return normalizedURL, nil
}

