}

// generateSecureState creates a cryptographically secure random state string
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectURL validates the redirect URL against a whitelist and ensures it's safe
func validateRedirectURL(redirectPath string) (string, error) {
	// If empty, use the default from config
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Parse the URL to validate its structure
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid URL format: %w", err)
	}

	// If the URL is not absolute, try to make it absolute by prepending the scheme and host from default config
	if !parsedURL.IsAbs() {
