		if err != nil {
			return "", fmt.Errorf("redirect URL must be absolute")
		}

		// Construct absolute URL using default scheme and host
		parsedURL.Scheme = defaultURL.Scheme
		parsedURL.Host = defaultURL.Host

		// Ensure path starts with /
		if !strings.HasPrefix(redirectPath, "/") {
			redirectPath = "/" + redirectPath
		}
		parsedURL.Path = redirectPath
	}

	// Ensure HTTPS scheme (allow http only for localhost in testing)
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return "", fmt.Errorf("redirect URL must use HTTPS or HTTP")
	}

	// Normalize the URL
	normalizedURL := parsedURL.String()
	normalizedURL = strings.TrimSuffix(normalizedURL, "/")

	// Check against whitelist
	if !allowedRedirectPaths[normalizedURL] && !allowedRedirectPaths[normalizedURL+"/"] {
