import (
	"crypto/rand"
	"encoding/base64"
	"errors"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// Whitelist of allowed redirect paths for security
var allowedRedirectPaths = []string{
	"https://yourapp.com/callback",
	"https://yourapp.com/auth/callback",
	"http://localhost:8080/callback",
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Use default redirect URL if empty
	if redirectPath == "" {
		redirectPath = OAuthConfig.RedirectURL
	}

	// Validate the redirect path against whitelist
	if !isValidRedirectURL(redirectPath) {
		return "", errors.New("invalid redirect URL: not in whitelist")
	}

	// Generate a cryptographically secure random state token
	state, err := generateSecureState()
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL with the secure state
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	// Set the state in a secure cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   false,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiry
	})

	return authURL, nil
}

// generateSecureState creates a cryptographically secure random state token
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// isValidRedirectURL validates the redirect URL against a whitelist
func isValidRedirectURL(redirectURL string) bool {
	// Parse the provided URL
	parsedURL, err := url.Parse(redirectURL)
	if err != nil {
		return false
	}

	// Ensure it's an absolute URL with https or http scheme (for localhost testing)
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return false
	}

	// Check against whitelist
	for _, allowed := range allowedRedirectPaths {
		allowedParsed, err := url.Parse(allowed)
		if err != nil {
			continue
		}

		// Match scheme, host, and path
		if parsedURL.Scheme == allowedParsed.Scheme &&
			strings.EqualFold(parsedURL.Host, allowedParsed.Host) &&
			parsedURL.Path == allowedParsed.Path {
			return true
		}
	}

	return false
}

