package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "http://localhost:8080/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state token
	state, err := generateSecureState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state token: %w", err)
	}

	// Validate and sanitize the redirectPath to prevent open redirect vulnerabilities
	validatedRedirectURL, err := validateRedirectURL(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL

	// Generate the authorization URL with the secure state
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	// Set the state in a secure cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration
	})

	return authURL, nil
}

// generateSecureState creates a cryptographically secure random state token
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectURL validates that the redirect URL is safe to use
func validateRedirectURL(redirectPath string) (string, error) {
	// If empty, use the default from config
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Parse the provided URL
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid URL format: %w", err)
	}

	// Parse the base config URL for comparison
	baseURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("invalid base URL configuration: %w", err)
	}

	// Security checks:
	// 1. Scheme must be https (or http only for localhost in development)
	if parsedURL.Scheme == "http" && !isLocalhost(parsedURL.Host) {
		return "", fmt.Errorf("redirect URL must use HTTPS")
	}

	// 2. Host must match the configured base host (prevent open redirect)
	if parsedURL.Host != "" && !isSameHost(parsedURL.Host, baseURL.Host) {
		return "", fmt.Errorf("redirect URL host does not match configured host")
	}

	// 3. If only path is provided, construct full URL with base host
	if parsedURL.Host == "" {
		// Ensure path starts with /
		if !strings.HasPrefix(redirectPath, "/") {
			redirectPath = "/" + redirectPath
		}
		return baseURL.Scheme + "://" + baseURL.Host + redirectPath, nil
	}

	return parsedURL.String(), nil
}

// isLocalhost checks if the host is localhost (for development)
func isLocalhost(host string) bool {
	return strings.HasPrefix(host, "localhost:") ||
		strings.HasPrefix(host, "127.0.0.1:") ||
		host == "localhost" ||
		host == "127.0.0.1"
}

// isSameHost checks if two hosts are the same
func isSameHost(host1, host2 string) bool {
	// Normalize by removing port for comparison if needed
	h1 := strings.Split(host1, ":")[0]
	h2 := strings.Split(host2, ":")[0]
	return strings.EqualFold(h1, h2)
}

