func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state
	state, err := generateSecureState()
	if err != nil {
		return "", err
	}

	// Use the default redirect URL from OAuthConfig if redirectPath is empty
	redirectURL := OAuthConfig.RedirectURL
	if redirectPath != "" {
		// Validate the redirectPath to prevent open redirect vulnerabilities
		if err := validateRedirectPath(redirectPath); err != nil {
			return "", err
		}
		redirectURL = redirectPath
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate the authorization URL with the random state
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	// Set the state in a secure cookie for later validation
	if w != nil {
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
			MaxAge:   600, // 10 minutes expiration
		})
	}

	return authURL, nil
}

// generateSecureState generates a cryptographically secure random state parameter
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectPath validates that the redirect path is safe to use
func validateRedirectPath(redirectPath string) error {
	if redirectPath == "" {
		return errors.New("redirect path cannot be empty")
	}

	// Parse the URL
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return errors.New("invalid redirect URL format")
	}

	// Ensure the URL is absolute
	if !parsedURL.IsAbs() {
		return errors.New("redirect URL must be absolute")
	}

	// Validate against allowed domains (whitelist approach)
	allowedHosts := []string{
		"yourapp.com",
		"www.yourapp.com",
		"example.com",
		"localhost",
		// Add other trusted domains here
	}

	// Check if the host is in the whitelist
	hostMatched := false
	for _, allowedHost := range allowedHosts {
		if strings.EqualFold(parsedURL.Host, allowedHost) || strings.HasSuffix(parsedURL.Host, ":"+strings.Split(parsedURL.Host, ":")[len(strings.Split(parsedURL.Host, ":"))-1]) && strings.EqualFold(strings.Split(parsedURL.Host, ":")[0], allowedHost) {
			hostMatched = true
			break
		}
	}

	if !hostMatched {
		return errors.New("redirect URL host not allowed")
	}

	// Ensure HTTPS is used (allow http for localhost in development)
	if parsedURL.Scheme != "https" && parsedURL.Scheme != "http" {
		return errors.New("redirect URL must use HTTPS or HTTP")
	}

	return nil
}

