	"encoding/base64"
	"errors"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate the redirectPath to prevent open redirect vulnerabilities
	if err := validateRedirectPath(redirectPath); err != nil {
		return "", err
	}

	// Generate a cryptographically secure random state token
	state, err := generateSecureState()
	if err != nil {
		return "", err
	}

	// Use the configured RedirectURL, not the user-provided one
	// The redirectPath can be stored in the state or session for post-auth routing
	config := *OAuthConfig

	// Generate the authorization URL with the secure state
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiry
	})

	// Optionally store the validated redirectPath in a separate cookie for post-auth routing
	if redirectPath != "" {
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_redirect",
			Value:    redirectPath,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
			MaxAge:   600, // 10 minutes expiry
		})
	}

	return authURL, nil
}

// generateSecureState creates a cryptographically secure random state token
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectPath ensures the redirect path is safe and relative
func validateRedirectPath(redirectPath string) error {
	if redirectPath == "" {
		return nil // Empty is acceptable, will use default
	}

	// Parse the redirect path
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return errors.New("invalid redirect path format")
	}

	// Only allow relative paths (no scheme or host)
	if parsedURL.Scheme != "" || parsedURL.Host != "" {
		return errors.New("redirect path must be relative")
	}

	// Ensure it starts with /
	if !strings.HasPrefix(redirectPath, "/") {
		return errors.New("redirect path must start with /")
	}

	// Additional validation: prevent protocol-relative URLs
	if strings.HasPrefix(redirectPath, "//") {
		return errors.New("protocol-relative URLs not allowed")
	}

	return nil
}

